func buildEmployeeQueryString(filter models.EmployeeFilter) string {
	params := []string{}
	if filter.Name.Set && filter.Name.Value != "" {
		params = append(params, "name="+filter.Name.Value)
	}
	if filter.JobTitle.Set && filter.JobTitle.Value != "" {
		params = append(params, "job_title="+string(filter.JobTitle.Value))
	}
	if filter.Status.Set && filter.Status.Value != "" {
		params = append(params, "status="+string(filter.Status.Value))
	}
	if filter.SalaryMin.Set {
		params = append(params, "salary_min="+filter.SalaryMin.Value.String())
	}
	if filter.SalaryMax.Set {
		params = append(params, "salary_max="+filter.SalaryMax.Value.String())
	}
	if filter.SortBy.Set {
		params = append(params, "sort="+filter.SortBy.Value)
	}
	if filter.SortOrder.Set {
		params = append(params, "order="+filter.SortOrder.Value)
	}
	return strings.Join(params, "&")
}

func buildEmployeePageURL(baseQuery string, page int) string {
	if baseQuery == "" {
		return fmt.Sprintf("/employees?page=%d", page)
	}
	return fmt.Sprintf("/employees?%s&page=%d", baseQuery, page)
}

